    (total, item) => total + item.unitPrice * item.quantity,
    0,
  );
}

function applyDiscounts(order: Order, amount: number): number {
  return DISCOUNTS.reduce(
    (running, discount) =>
      discount.applies(order) ? running * discount.factor : running,
    amount,
  );
}

function applyTax(amount: number, vatRate: number): number {
  return amount * (1 + vatRate);
}

function round(amount: number): number {
  return Math.round(amount * 100) / 100;
}

const STAGES: {
  name: string;
  run(amount: number, order: Order, vatRate: number): number;
}[] = [
  { name: "subtotal", run: (_amount, order) => subtotal(order) },
  { name: "discount", run: (amount, order) => applyDiscounts(order, amount) },
  { name: "tax", run: (amount, _order, vatRate) => applyTax(amount, vatRate) },
  { name: "rounding", run: (amount) => round(amount) },
];

function runPipeline(
  order: Order,
  vatRate: number,
  hooks: PricingHooks,
): number {
  let amount = 0;
  for (const stage of STAGES) {
    hooks.beforeStage?.(stage.name);
    amount = stage.run(amount, order, vatRate);
    hooks.afterStage?.(stage.name, amount);
  }
  return amount;
}

